  IonIcon
} from '@ionic/react';
import { flashOutline, speedometerOutline, pulseOutline } from 'ionicons/icons';
import ApexCharts from 'apexcharts';
import '../components/EnergyConsumption.css'; // Reusing global styles from the energy dashboard

const PowerMonitoring: React.FC = () => {
  const chartRef1 = useRef<HTMLDivElement | null>(null);
  const chartRef2 = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    let powerChart: ApexCharts | null = null;
    let voltageChart: ApexCharts | null = null;

    if (chartRef1.current) {
      powerChart = new ApexCharts(chartRef1.current, {
        chart: { type: 'radialBar', height: 350, animations: { enabled: true, easing: 'linear', dynamicAnimation: { speed: 1000 } } },
        series: [92], // Power factor
        colors: ['#2563eb'],
        plotOptions: {
          radialBar: {
            hollow: { size: '65%' },
            dataLabels: {
              name: { show: true, fontSize: '16px', color: '#64748b' },
              value: { show: true, fontSize: '36px', fontWeight: 'bold' }
            }
          }
        },
        labels: ['Power Factor'],
      });
      powerChart.render();
    }

    if (chartRef2.current) {
      voltageChart = new ApexCharts(chartRef2.current, {
        chart: { type: 'area', height: 300, toolbar: { show: false }, animations: { enabled: true, easing: 'linear', dynamicAnimation: { speed: 1000 } } },
        stroke: { curve: 'smooth', width: 2 },
        series: [{ name: 'Voltage (V)', data: [225, 230, 228, 229, 232, 230, 228, 229] }],
        colors: ['#059669'],
        xaxis: { categories: ['10:00', '10:05', '10:10', '10:15', '10:20', '10:25', '10:30', '10:35'] },
        yaxis: { min: 210, max: 250 },
        dataLabels: { enabled: false },
        fill: { type: 'gradient', gradient: { shadeIntensity: 1, opacityFrom: 0.4, opacityTo: 0.05 } }
      });
      voltageChart.render();
    }

    const interval = setInterval(() => {
      const pf = Math.floor(Math.random() * (99 - 85 + 1) + 85);
      if (powerChart) powerChart.updateSeries([pf]);

      if (voltageChart) {
        const v = Math.floor(Math.random() * (235 - 225 + 1) + 225);
        voltageChart.appendData([{ data: [v] }]);
      }
    }, 3000);

    return () => {
      clearInterval(interval);
      powerChart?.destroy();
      voltageChart?.destroy();
    };
  }, []);

  return (
    <IonPage>
      <IonHeader>
        <IonToolbar>
          <IonButtons slot="start">
            <IonMenuButton color="primary" />
          </IonButtons>
          <IonTitle>Power Monitoring</IonTitle>
        </IonToolbar>
      </IonHeader>
      <IonContent fullscreen className="ion-padding" style={{ '--background': '#f8fafc' }}>
        <div className="energy-inner" style={{ paddingTop: '1rem' }}>

          <div className="energy-widgets">
            <IonCard className="widget-card">
              <div className="widget-title"><IonIcon icon={flashOutline} /> Real-time Voltage</div>
              <div className="widget-value">229.4 <span style={{ fontSize: '1rem', color: '#64748b' }}>V</span></div>
              <div className="widget-sub">Stable within bounds</div>
            </IonCard>
            <IonCard className="widget-card">
              <div className="widget-title"><IonIcon icon={pulseOutline} /> Current Draw</div>
              <div className="widget-value">46.2 <span style={{ fontSize: '1rem', color: '#64748b' }}>Amps</span></div>
              <div className="widget-sub">Nominal load</div>
            </IonCard>
            <IonCard className="widget-card">
              <div className="widget-title"><IonIcon icon={speedometerOutline} /> Frequency</div>
              <div className="widget-value">50.02 <span style={{ fontSize: '1rem', color: '#64748b' }}>Hz</span></div>
              <div className="widget-sub">Optimal generation</div>
            </IonCard>
          </div>

          <div className="energy-grid">
            <IonCard className="energy-card">
              <div className="card-head">
                <div className="card-title">Power Factor (Real-time PF)</div>
                <div className="card-badge">Active</div>
              </div>
              <div ref={chartRef1} style={{ padding: '1rem 0' }}></div>
            </IonCard>

            <IonCard className="energy-card">
              <div className="card-head">
                <div className="card-title">Voltage Fluctuations</div>
                <div className="card-badge">Live</div>
              </div>
              <div ref={chartRef2} style={{ padding: '1rem 0' }}></div>
            </IonCard>
          </div>

        </div>
      </IonContent>
    </IonPage>
  );
};

