{"content":"import React, { useEffect, useRef, useState } from 'react';
import {
  IonButtons,
  IonContent,
  IonHeader,
  IonMenuButton,
  IonPage,
  IonTitle,
  IonToolbar,
  IonCard,
  IonIcon
} from '@ionic/react';
import { barChartOutline, pulseOutline, calendarOutline, speedometerOutline } from 'ionicons/icons';
import ApexCharts from 'apexcharts';
import '../components/EnergyConsumption.css';
import TimeRangeModal from '../components/TimeRangeModal';

const MachineComparison: React.FC = () => {
  const barChartRef = useRef<HTMLDivElement | null>(null);

  const [isModalOpen, setModalOpen] = useState(false);
  const [selectedRange, setSelectedRange] = useState("5m");
  const [selectedRangeLabel, setSelectedRangeLabel] = useState("5 min");
  const [customRange, setCustomRange] = useState<{start: string, end: string} | null>(null);

  const handleSelectRange = (
    range: string,
    label: string,
    selectedCustomRange?: {start: string, end: string}
  ) => {
    setSelectedRange(range);
    setSelectedRangeLabel(label);
    setCustomRange(range === "custom" && selectedCustomRange ? selectedCustomRange : null);
  };

  useEffect(() => {
    let comparisonChart: ApexCharts | null = null;

    let stepMs = 60000; 
    let pointCount = 6;

    switch(selectedRange) {
      case '5m': stepMs = 60000; pointCount = 6; break;
      case '30m': stepMs = 5 * 60000; pointCount = 7; break;
      case '6h': stepMs = 60 * 60000; pointCount = 7; break;
      case '12h': stepMs = 2 * 60 * 60000; pointCount = 7; break;
      case '24h': stepMs = 4 * 60 * 60000; pointCount = 7; break;
      case 'thisWeek': case 'lastWeek': stepMs = 24 * 60 * 60000; pointCount = 7; break;
      case 'thisMonth': case 'lastMonth': stepMs = 5 * 24 * 60 * 60000; pointCount = 7; break;
      case 'custom':
        if (customRange) {
            const s = new Date(customRange.start).getTime();
            const e = new Date(customRange.end).getTime();
            stepMs = Math.max(60000, (e - s) / 6);
            pointCount = 7;
        }
        break;
      default: stepMs = 60000; pointCount = 6; 
    }

    const categories: number[] = [];
    const dataM1: number[] = [];
    const dataM2: number[] = [];
    const dataM3: number[] = [];
    const now = Date.now();

    let xAxisFormat = "HH:mm";
    if (['thisWeek', 'lastWeek', 'thisMonth', 'lastMonth'].includes(selectedRange)) {
        xAxisFormat = "dd MMM";
    } else if (selectedRange === 'custom' && customRange) {
        const diffMs = new Date(customRange.end).getTime() - new Date(customRange.start).getTime();
        if (diffMs > 24 * 60 * 60 * 1000) xAxisFormat = "dd MMM";
    }

    for (let i = pointCount - 1; i >= 0; i--) {
      categories.push(now - i * stepMs);
      dataM1.push(parseFloat((Math.random() * (45 - 35) + 35).toFixed(1)));
      dataM2.push(parseFloat((Math.random() * (50 - 40) + 40).toFixed(1)));
      dataM3.push(parseFloat((Math.random() * (30 - 20) + 20).toFixed(1)));
    }

    if (barChartRef.current) {
      comparisonChart = new ApexCharts(barChartRef.current, {
        chart: { type: 'bar', height: 350, toolbar: { show: false }, animations: { enabled: true, dynamicAnimation: { speed: 1000 } } },
        series: [
          { name: 'Machine 1', data: [...dataM1] },
          { name: 'Machine 2', data: [...dataM2] },
          { name: 'Machine 3', data: [...dataM3] }
        ],
        colors: ['#4f46e5', '#10b981', '#f59e0b'],
        xaxis: { 
          type: 'datetime',
          categories: [...categories],
          labels: {
            datetimeUTC: false,
            format: xAxisFormat
          }
        },
        dataLabels: { enabled: false },
        tooltip: { x: { format: 'dd MMM yyyy, HH:mm' } },
        plotOptions: { bar: { borderRadius: 2, columnWidth: '60%' } }
      });
      comparisonChart.render();
    }

    const interval = setInterval(() => {
      if (comparisonChart) {
        categories.shift();
        categories.push(Date.now());

        dataM1.shift();
        dataM1.push(parseFloat((Math.random() * (45 - 35) + 35).toFixed(1)));

        dataM2.shift();
        dataM2.push(parseFloat((Math.random() * (50 - 40) + 40).toFixed(1)));

        dataM3.shift();
        dataM3.push(parseFloat((Math.random() * (30 - 20) + 20).toFixed(1)));

        comparisonChart.updateOptions({ xaxis: { categories: [...categories] } }, false, false);
        comparisonChart.updateSeries([
          { name: 'Machine 1', data: [...dataM1] },
          { name: 'Machine 2', data: [...dataM2] },
          { name: 'Machine 3', data: [...dataM3] }
        ], true);
      }
    }, 60000);

    return () => {
      clearInterval(interval);
      comparisonChart?.destroy();
    };
  }, [selectedRange, customRange]);

  return (
    <IonPage>
      <IonHeader>
        <IonToolbar>
          <IonButtons slot="start">
            <IonMenuButton color="primary" />
          </IonButtons>
          <IonTitle>Machine Comparison</IonTitle>
        </IonToolbar>
      </IonHeader>
      <IonContent fullscreen className="ion-padding" style={{ '--background': '#f8fafc' }}>
        <div className="energy-inner" style={{ paddingTop: '1rem' }}>

          <div className="energy-title-row">
            <button className="time-range-button" onClick={() => setModalOpen(true)}>
              <IonIcon icon={calendarOutline} />
              <span>{selectedRangeLabel}</span>
            </button>
          </div>

          <div className="energy-widgets">
            <IonCard className="widget-card">
              <div className="widget-title"><IonIcon icon={barChartOutline} /> Peak Consumer</div>
              <div className="widget-value">Machine 2</div>
              <div className="widget-sub negative">▲ 12% higher than average</div>
            </IonCard>
            <IonCard className="widget-card">
              <div className="widget-title"><IonIcon icon={speedometerOutline} /> Most Efficient</div>
              <div className="widget-value">Machine 3</div>
              <div className="widget-sub">Operating at optimal load</div>
            </IonCard>
            <IonCard className="widget-card">
              <div className="widget-title"><IonIcon icon={pulseOutline} /> Total Factory Load</div>
              <div className="widget-value">121.5 <span style={{ fontSize: '0.8rem', color: '#64748b' }}>kW</span></div>
              <div className="widget-sub">Aligned with shift target</div>
            </IonCard>
          </div>

          <div className="energy-grid">
            <IonCard className="energy-card" style={{ gridColumn: 'span 2' }}>
              <div className="card-head">
                <div className="card-title">Load Distribution Comparison</div>
                <div className="card-badge">History</div>
              </div>
              <div ref={barChartRef} style={{ padding: '1rem 0' }}></div>
            </IonCard>
          </div>

        </div>
      </IonContent>

      <TimeRangeModal
        isOpen={isModalOpen}
        onClose={() => setModalOpen(false)}
        onSelect={handleSelectRange}
        selectedRange={selectedRange}
        theme="light"
      />
    </IonPage>
